11â†’// BatchQuery is a parameterized SQL statement with its arguments.
12â†’type BatchQuery struct {
13â†’	SQL  string
14â†’	Args []any
15â†’}
16â†’
17â†’// BatchExec sends all queries as a single pgx batch, executing them within one
18â†’// round-trip. Returns the first error encountered across all results.
19â†’func BatchExec(ctx context.Context, pool *pgxpool.Pool, queries []BatchQuery) error {
20â†’	if len(queries) == 0 {
21â†’		return nil
22â†’	}
23â†’
24â†’	batch := &pgx.Batch{}
25â†’	for _, q := range queries {
26â†’		batch.Queue(q.SQL, q.Args...)
27â†’	}
28â†’
29â†’	results := pool.SendBatch(ctx, batch)
30â†’	defer results.Close()
31â†’
32â†’	for i := range queries {
33â†’		if _, err := results.Exec(); err != nil {
34â†’			return fmt.Errorf("dbutil: batch exec query %d: %w", i, err)
35â†’		}
36â†’	}
37â†’	return nil
38â†’}
39â†’
40â†’// CopyFrom bulk-inserts rows into the given table using PostgreSQL's COPY
41â†’// protocol. Returns the number of rows inserted.
42â†’func CopyFrom(ctx context.Context, pool *pgxpool.Pool, tableName pgx.Identifier, columns []string, rows [][]any) (int64, error) {
43â†’	rowSrc := pgx.CopyFromRows(rows)
44â†’	n, err := pool.CopyFrom(ctx, tableName, columns, rowSrc)
45â†’	if err != nil {
46â†’		return 0, fmt.Errorf("dbutil: copy from %s: %w", tableName.Sanitize(), err)
47â†’	}
48â†’	return n, nil
49â†’}
