  1â†’// Package fetch provides an HTTP fetcher with local archive caching for
  2â†’// downloading data source files used by the kapow import pipelines.
  3â†’package fetch
  4â†’
  5â†’import (
  6â†’	"archive/zip"
  7â†’	"bytes"
  8â†’	"compress/gzip"
  9â†’	"context"
 10â†’	"encoding/json"
 11â†’	"fmt"
 12â†’	"io"
 13â†’	"log/slog"
 14â†’	"net/http"
 15â†’	"os"
 16â†’	"os/exec"
 17â†’	"path/filepath"
 18â†’	"sort"
 19â†’	"strings"
 20â†’	"time"
 21â†’)
 22â†’
 23â†’// FetchConfig describes how to retrieve a data source file.
 24â†’type FetchConfig struct {
 25â†’	// Name is a short identifier (e.g. "nces") used in archive filenames.
 26â†’	Name string
 27â†’	// URL is the HTTP URL to download from.
 28â†’	URL string
 29â†’	// Format is the source format before re-compression: "csv", "csv.gz", "gz", "zip".
 30â†’	Format string
 31â†’}
 32â†’
 33â†’// cacheEntry is persisted as a JSON sidecar alongside each archive file.
 34â†’// It stores the HTTP cache validators from the last successful download so
 35â†’// that subsequent requests can use conditional GET (ETag / Last-Modified).
 36â†’type cacheEntry struct {
 37â†’	ETag         string `json:"etag,omitempty"`
 38â†’	LastModified string `json:"last_modified,omitempty"`
 39â†’	File         string `json:"file"` // absolute path to the .xz archive
 40â†’}
 41â†’
 42â†’// Fetcher downloads and caches source data files. It stores downloaded files
 43â†’// as xz-compressed archives in a local cache directory to avoid redundant
 44â†’// downloads across runs.
 45â†’type Fetcher struct {
 46â†’	cacheDir   string
 47â†’	httpClient *http.Client
 48â†’}
 49â†’
 50â†’// New creates a Fetcher that stores cached downloads in the given directory.
 51â†’func New(cacheDir string) *Fetcher {
 52â†’	return &Fetcher{
 53â†’		cacheDir:   cacheDir,
 54â†’		httpClient: &http.Client{},
 55â†’	}
 56â†’}
 57â†’
 58â†’// CacheDir returns the directory used for cached downloads.
 59â†’func (f *Fetcher) CacheDir() string {
 60â†’	return f.cacheDir
 61â†’}
 62â†’
 63â†’// Fetch retrieves the data source described by cfg, returning a reader over
 64â†’// the raw (decompressed) content. The caller is responsible for closing the
 65â†’// returned reader.
 66â†’//
 67â†’// Fetch logic:
 68â†’//  1. If no sidecar exists, check for manually-dropped archive files and
 69â†’//     return the newest one without hitting the network.
 70â†’//  2. Perform a conditional HTTP GET using ETag / Last-Modified from the
 71â†’//     sidecar when available.
 72â†’//  3. On 304 Not Modified, return the existing cached archive.
 73â†’//  4. On network error, fall back to the stale cached archive (if present)
 74â†’//     with a warning log.
 75â†’//  5. On 200 OK, decompress the source body, re-compress with xz -9e, save
 76â†’//     the archive and sidecar, and return the decompressed content.
 77â†’func (f *Fetcher) Fetch(ctx context.Context, cfg FetchConfig) (io.ReadCloser, error) {
 78â†’	if err := os.MkdirAll(f.cacheDir, 0o755); err != nil {
 79â†’		return nil, fmt.Errorf("fetch: create cache dir: %w", err)
 80â†’	}
 81â†’
 82â†’	storedExt := storedFormat(cfg.Format)
 83â†’	sidecarPath := filepath.Join(f.cacheDir, cfg.Name+".cache.json")
 84â†’	entry, _ := loadSidecar(sidecarPath)
 85â†’
 86â†’	// 1. When there is no sidecar, check for manually-dropped archive files.
 87â†’	//    This lets operators place hand-obtained files in the cache directory
 88â†’	//    for sources that cannot be downloaded automatically.
 89â†’	if entry == nil {
 90â†’		if path, ok := f.Latest(cfg.Name, storedExt); ok {
 91â†’			slog.Info("fetch: using manually-dropped file", "source", cfg.Name, "path", path)
 92â†’			return openXZ(ctx, path)
 93â†’		}
 94â†’	}
 95â†’
 96â†’	// 2. Build HTTP request, adding conditional headers from the sidecar.
 97â†’	req, err := http.NewRequestWithContext(ctx, http.MethodGet, cfg.URL, nil)
 98â†’	if err != nil {
 99â†’		return nil, fmt.Errorf("fetch: build request: %w", err)
100â†’	}
101â†’	if entry != nil {
102â†’		if entry.ETag != "" {
103â†’			req.Header.Set("If-None-Match", entry.ETag)
104â†’		}
105â†’		if entry.LastModified != "" {
106â†’			req.Header.Set("If-Modified-Since", entry.LastModified)
107â†’		}
108â†’	}
109â†’
110â†’	resp, httpErr := f.httpClient.Do(req)
111â†’
112â†’	// 4. On network error, fall back to stale cache.
113â†’	if httpErr != nil {
114â†’		if entry != nil && entry.File != "" {
115â†’			if _, statErr := os.Stat(entry.File); statErr == nil {
116â†’				slog.Warn("fetch: network error, using stale cache",
117â†’					"source", cfg.Name, "file", entry.File, "error", httpErr)
118â†’				return openXZ(ctx, entry.File)
119â†’			}
120â†’		}
121â†’		return nil, fmt.Errorf("fetch: http get %s: %w", cfg.Name, httpErr)
122â†’	}
123â†’	defer resp.Body.Close()
124â†’
125â†’	// 3. Handle 304 Not Modified â€” content unchanged, return existing archive.
126â†’	if resp.StatusCode == http.StatusNotModified {
127â†’		if entry != nil && entry.File != "" {
128â†’			if _, statErr := os.Stat(entry.File); statErr == nil {
129â†’				slog.Info("fetch: content unchanged (304), using cached file",
130â†’					"source", cfg.Name, "file", entry.File)
131â†’				return openXZ(ctx, entry.File)
132â†’			}
133â†’		}
134â†’		return nil, fmt.Errorf("fetch: received 304 but no cached file for %s", cfg.Name)
135â†’	}
136â†’
137â†’	// Stale fallback for unexpected non-200 responses.
138â†’	if resp.StatusCode != http.StatusOK {
139â†’		if entry != nil && entry.File != "" {
140â†’			if _, statErr := os.Stat(entry.File); statErr == nil {
141â†’				slog.Warn("fetch: non-OK status, using stale cache",
142â†’					"source", cfg.Name, "status", resp.StatusCode, "file", entry.File)
143â†’				return openXZ(ctx, entry.File)
144â†’			}
145â†’		}
146â†’		return nil, fmt.Errorf("fetch: unexpected status %d for %s", resp.StatusCode, cfg.Name)
147â†’	}
148â†’
149â†’	// 5. Download: decompress source body, re-compress with xz, save archive.
150â†’	decompressed, err := decompressSource(resp.Body, cfg.Format)
151â†’	if err != nil {
152â†’		return nil, fmt.Errorf("fetch: decompress source %s: %w", cfg.Name, err)
153â†’	}
154â†’	defer decompressed.Close()
155â†’
156â†’	// Buffer the decompressed data so we can both archive it and return it.
157â†’	data, err := io.ReadAll(decompressed)
158â†’	if err != nil {
159â†’		return nil, fmt.Errorf("fetch: read body %s: %w", cfg.Name, err)
160â†’	}
161â†’
162â†’	archiveFile := filepath.Join(f.cacheDir,
163â†’		fmt.Sprintf("%s-%s.%s.xz", cfg.Name, time.Now().UTC().Format("2006-01-02"), storedExt))
164â†’
165â†’	if err := compressXZ(ctx, bytes.NewReader(data), archiveFile); err != nil {
166â†’		return nil, fmt.Errorf("fetch: compress archive %s: %w", cfg.Name, err)
167â†’	}
168â†’
169â†’	newEntry := &cacheEntry{
170â†’		ETag:         resp.Header.Get("ETag"),
171â†’		LastModified: resp.Header.Get("Last-Modified"),
172â†’		File:         archiveFile,
173â†’	}
174â†’	if err := saveSidecar(sidecarPath, newEntry); err != nil {
175â†’		slog.Warn("fetch: failed to save sidecar", "path", sidecarPath, "error", err)
176â†’	}
177â†’
178â†’	slog.Info("fetch: downloaded and archived",
179â†’		"source", cfg.Name, "file", archiveFile, "bytes", len(data))
180â†’
181â†’	return io.NopCloser(bytes.NewReader(data)), nil
182â†’}
183â†’
184â†’// Latest returns the path to the most recently dated archive file matching
185â†’// "{name}-*.{ext}.xz" in the cache directory. Returns ("", false) if none exist.
186â†’//
187â†’// Files are named with ISO dates (e.g. nces-2026-03-09.csv.xz) so lexicographic
188â†’// sort gives the correct newest-first order.
189â†’func (f *Fetcher) Latest(name, ext string) (string, bool) {
190â†’	pattern := filepath.Join(f.cacheDir, fmt.Sprintf("%s-*.%s.xz", name, ext))
191â†’	matches, err := filepath.Glob(pattern)
192â†’	if err != nil || len(matches) == 0 {
193â†’		return "", false
194â†’	}
195â†’	sort.Strings(matches)
196â†’	return matches[len(matches)-1], true
197â†’}
198â†’
199â†’// storedFormat returns the archive extension for a given source format,
200â†’// stripping any outer compression layer (e.g. "csv.gz" â†’ "csv").
201â†’func storedFormat(format string) string {
202â†’	switch strings.ToLower(format) {
203â†’	case "csv.gz", "gz":
204â†’		return "csv"
205â†’	case "zip":
206â†’		return "csv"
207â†’	default:
208â†’		return format
209â†’	}
210â†’}
211â†’
212â†’// decompressSource wraps r in the appropriate decompressor for the source format.
213â†’// The caller is responsible for closing the returned ReadCloser.
214â†’func decompressSource(r io.Reader, format string) (io.ReadCloser, error) {
215â†’	switch strings.ToLower(format) {
216â†’	case "csv.gz", "gz":
217â†’		gr, err := gzip.NewReader(r)
218â†’		if err != nil {
219â†’			return nil, fmt.Errorf("open gzip reader: %w", err)
220â†’		}
221â†’		return gr, nil
222â†’
223â†’	case "zip":
224â†’		// archive/zip requires a ReaderAt; buffer the entire body first.
225â†’		data, err := io.ReadAll(r)
226â†’		if err != nil {
227â†’			return nil, fmt.Errorf("buffer zip body: %w", err)
228â†’		}
229â†’		zr, err := zip.NewReader(bytes.NewReader(data), int64(len(data)))
230â†’		if err != nil {
231â†’			return nil, fmt.Errorf("open zip: %w", err)
232â†’		}
233â†’		if len(zr.File) == 0 {
234â†’			return nil, fmt.Errorf("zip archive is empty")
235â†’		}
236â†’		rc, err := zr.File[0].Open()
237â†’		if err != nil {
238â†’			return nil, fmt.Errorf("open zip entry: %w", err)
239â†’		}
240â†’		return rc, nil
241â†’
242â†’	default:
243â†’		// Plain format (csv, tsv, â€¦) â€” pass through unchanged.
244â†’		return io.NopCloser(r), nil
245â†’	}
246â†’}
247â†’
248â†’// compressXZ reads from src and writes an xz-compressed file to dst using the
249â†’// system xz binary with -9e (maximum/extreme compression).
250â†’func compressXZ(ctx context.Context, src io.Reader, dst string) error {
251â†’	f, err := os.Create(dst)
252â†’	if err != nil {
253â†’		return fmt.Errorf("create xz output: %w", err)
254â†’	}
255â†’	defer f.Close()
256â†’
257â†’	var stderr bytes.Buffer
258â†’	cmd := exec.CommandContext(ctx, "xz", "-9e", "-c") //nolint:gosec
259â†’	cmd.Stdin = src
260â†’	cmd.Stdout = f
261â†’	cmd.Stderr = &stderr
262â†’
263â†’	if err := cmd.Run(); err != nil {
264â†’		_ = os.Remove(dst)
265â†’		return fmt.Errorf("xz: %w: %s", err, strings.TrimSpace(stderr.String()))
266â†’	}
267â†’	return nil
268â†’}
269â†’
270â†’// openXZ returns a reader over the decompressed content of an xz archive using
271â†’// the system xz binary. The returned reader holds the entire decompressed
272â†’// content in memory.
273â†’func openXZ(ctx context.Context, path string) (io.ReadCloser, error) {
274â†’	var stderr bytes.Buffer
275â†’	cmd := exec.CommandContext(ctx, "xz", "-d", "-c", path) //nolint:gosec
276â†’	cmd.Stderr = &stderr
277â†’
278â†’	out, err := cmd.Output()
279â†’	if err != nil {
280â†’		return nil, fmt.Errorf("fetch: xz decompress %s: %w: %s",
281â†’			path, err, strings.TrimSpace(stderr.String()))
282â†’	}
283â†’	return io.NopCloser(bytes.NewReader(out)), nil
284â†’}
285â†’
286â†’// loadSidecar reads a cacheEntry from a JSON sidecar file.
287â†’// Returns (nil, err) if the file is absent or cannot be parsed.
288â†’func loadSidecar(path string) (*cacheEntry, error) {
289â†’	data, err := os.ReadFile(path)
290â†’	if err != nil {
291â†’		return nil, err
292â†’	}
293â†’	var entry cacheEntry
294â†’	if err := json.Unmarshal(data, &entry); err != nil {
295â†’		return nil, fmt.Errorf("fetch: unmarshal sidecar %s: %w", path, err)
296â†’	}
297â†’	return &entry, nil
298â†’}
299â†’
300â†’// saveSidecar writes a cacheEntry to a JSON sidecar file.
301â†’func saveSidecar(path string, entry *cacheEntry) error {
302â†’	data, err := json.MarshalIndent(entry, "", "  ")
303â†’	if err != nil {
304â†’		return fmt.Errorf("fetch: marshal sidecar: %w", err)
305â†’	}
306â†’	return os.WriteFile(path, data, 0o644) //nolint:gosec
307â†’}
308â†’

  1â†’package csvutil
  2â†’
  3â†’import (
  4â†’	"encoding/csv"
  5â†’	"fmt"
  6â†’	"io"
  7â†’	"strconv"
  8â†’)
  9â†’
 10â†’// Option configures a Reader.
 11â†’type Option func(*Reader)
 12â†’
 13â†’// WithDelimiter sets the field delimiter (default: ',').
 14â†’func WithDelimiter(r rune) Option {
 15â†’	return func(cr *Reader) {
 16â†’		cr.csv.Comma = r
 17â†’	}
 18â†’}
 19â†’
 20â†’// WithLazyQuotes allows bare quotes in non-quoted fields and non-doubled quotes
 21â†’// in quoted fields (encoding/csv LazyQuotes mode).
 22â†’func WithLazyQuotes(b bool) Option {
 23â†’	return func(cr *Reader) {
 24â†’		cr.csv.LazyQuotes = b
 25â†’	}
 26â†’}
 27â†’
 28â†’// Reader wraps encoding/csv and maps columns by header name.
 29â†’// Call Next to iterate rows; each row provides named-column accessors.
 30â†’type Reader struct {
 31â†’	csv     *csv.Reader
 32â†’	headers map[string]int
 33â†’}
 34â†’
 35â†’// NewReader creates a Reader, reads the first line as column headers, and
 36â†’// applies any provided options. Returns an error if the header row cannot be
 37â†’// read or parsed.
 38â†’func NewReader(r io.Reader, opts ...Option) (*Reader, error) {
 39â†’	cr := &Reader{
 40â†’		csv: csv.NewReader(r),
 41â†’	}
 42â†’	// Apply options before reading headers so delimiter etc. take effect.
 43â†’	for _, o := range opts {
 44â†’		o(cr)
 45â†’	}
 46â†’
 47â†’	headers, err := cr.csv.Read()
 48â†’	if err != nil {
 49â†’		return nil, fmt.Errorf("csvutil: read headers: %w", err)
 50â†’	}
 51â†’
 52â†’	cr.headers = make(map[string]int, len(headers))
 53â†’	for i, h := range headers {
